def load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def build_tenants(cfg: Dict[str, Any]) -> List[TenantSpec]:
    tenants: List[TenantSpec] = []
    for t in cfg.get("tenants", []):
        app = t.get("app") or t.get("name") or ""
        vhost = t.get("vhost") or f"/{app}"
        users: List[UserSpec] = []
        perms: Dict[str, PermissionSpec] = {}

        for u in t.get("users", []):
            us = UserSpec(
                name=u["name"],
                password=u.get("password"),
                tags=u.get("tags", ""),
            )
            users.append(us)

        for uname, p in (t.get("permissions") or {}).items():
            perms[uname] = PermissionSpec(
                configure=p.get("configure", "^$"),
                write=p.get("write", ".*"),
                read=p.get("read", ".*"),
            )

        tenants.append(TenantSpec(app=app, vhost=vhost, users=users, permissions=perms))
    return tenants


