def parse_args(argv: List[str]) -> argparse.Namespace:
    p = argparse.ArgumentParser(description="Configure RabbitMQ vhosts, users, and permissions via Management HTTP API.")
    p.add_argument("--api-url", default=os.getenv("RABBITMQ_API_URL", "http://localhost:15672"), help="Base URL, e.g. http://host:15672")
    p.add_argument("--api-user", default=os.getenv("RABBITMQ_API_USER", "guest"))
    p.add_argument("--api-pass", default=os.getenv("RABBITMQ_API_PASS", "guest"))
    p.add_argument("--config", default=os.getenv("RABBITMQ_TENANTS_CONFIG", ""), help="Path to JSON config file")
    p.add_argument("--insecure", action="store_true", help="Disable TLS verification")
    p.add_argument("--timeout", type=int, default=int(os.getenv("RABBITMQ_API_TIMEOUT", "15")))
    p.add_argument("--retries", type=int, default=int(os.getenv("RABBITMQ_API_RETRIES", "5")))
    p.add_argument("--retry-delay", type=float, default=float(os.getenv("RABBITMQ_API_RETRY_DELAY", "1.0")))
    p.add_argument("--print-example-config", action="store_true")
    return p.parse_args(argv)


def with_retries(fn, retries: int, delay: float):
    last_exc = None
    for i in range(retries):
        try:
            return fn()
        except Exception as e:
            last_exc = e
            if i < retries - 1:
                time.sleep(delay * (2 ** i))
    raise last_exc


